export const Dashboard: React.FC = () => {
  const [stats, setStats] = useState({
    totalClasses: 0,
    totalStudents: 0,
    passRate: 0,
    averageScore: 0
  });

  const [barData, setBarData] = useState<any>(null);
  const [pieData, setPieData] = useState<any>(null);

  useEffect(() => {
    const classes = getClasses();
    const students = getStudents();
    const grades = getGrades();

    let totalScore = 0;
    let passedCount = 0;
    let failedCount = 0;
    let gradedCount = 0;

    const classLabels: string[] = [];
    const classAvgScores: number[] = [];

    classes.forEach(cls => {
      classLabels.push(cls.name);
      const clsStudents = students.filter(s => s.classId === cls.id);
      let clsTotal = 0;
      let clsGraded = 0;

      clsStudents.forEach(student => {
        const grade = grades.find(g => g.studentId === student.id);
        if (grade) {
          const avgF = grade.formatif.reduce((a, b) => a + b, 0) / (grade.formatif.filter(n => n > 0).length || 1);
          const avgS = grade.sumatif.reduce((a, b) => a + b, 0) / (grade.sumatif.filter(n => n > 0).length || 1);
          const sas = (grade.sasNonTes + grade.sasTes) / 2;
          const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);

          if (final > 0) {
            totalScore += final;
            clsTotal += final;
            gradedCount++;
            clsGraded++;
            if (final >= KKM) {
              passedCount++;
            } else {
              failedCount++;
            }
          }
        }
      });

      classAvgScores.push(clsGraded > 0 ? parseFloat((clsTotal / clsGraded).toFixed(1)) : 0);
    });

    setStats({
      totalClasses: classes.length,
      totalStudents: students.length,
      passRate: gradedCount > 0 ? Math.round((passedCount / gradedCount) * 100) : 0,
      averageScore: gradedCount > 0 ? Math.round(totalScore / gradedCount) : 0
    });

    // Prepare Chart Data
    setBarData({
      labels: classLabels,
      datasets: [
        {
          label: 'Rata-rata Kelas',
          data: classAvgScores,
          backgroundColor: 'rgba(25, 135, 84, 0.7)', // Islamic Green
          borderColor: 'rgba(25, 135, 84, 1)',
          borderWidth: 1,
        },
      ],
    });

    setPieData({
      labels: ['Tuntas', 'Belum Tuntas'],
      datasets: [
        {
          data: [passedCount, failedCount],
          backgroundColor: [
            'rgba(25, 135, 84, 0.8)', // Green
            'rgba(220, 53, 69, 0.8)', // Red
          ],
          borderColor: [
            'rgba(25, 135, 84, 1)',
            'rgba(220, 53, 69, 1)',
          ],
          borderWidth: 1,
        },
      ],
    });

  }, []);

  return (
    <div className="container-fluid p-0">
      <h2 className="mb-4 text-dark border-bottom pb-2 font-arabic">Dashboard Statistik</h2>

      {/* Info Cards */}
      <div className="row g-3 mb-4">
        <div className="col-md-3">
          <div className="card card-dashboard h-100 bg-primary text-white">
            <div className="card-body">
              <h6 className="card-title opacity-75">Total Kelas</h6>
              <h2 className="mb-0 fw-bold">{stats.totalClasses}</h2>
            </div>
          </div>
        </div>
        <div className="col-md-3">
          <div className="card card-dashboard h-100 bg-success text-white">
            <div className="card-body">
              <h6 className="card-title opacity-75">Total Siswa</h6>
              <h2 className="mb-0 fw-bold">{stats.totalStudents}</h2>
            </div>
          </div>
        </div>
        <div className="col-md-3">
          <div className="card card-dashboard h-100 bg-warning text-dark">
            <div className="card-body">
              <h6 className="card-title opacity-75">Rata-rata Total</h6>
              <h2 className="mb-0 fw-bold">{stats.averageScore}</h2>
            </div>
          </div>
        </div>
        <div className="col-md-3">
          <div className="card card-dashboard h-100 bg-info text-white">
            <div className="card-body">
              <h6 className="card-title opacity-75">Ketuntasan</h6>
              <h2 className="mb-0 fw-bold">{stats.passRate}%</h2>
            </div>
          </div>
        </div>
      </div>

      {/* Charts */}
      <div className="row g-4">
        <div className="col-md-8">
          <div className="card card-dashboard shadow-sm">
            <div className="card-header bg-white fw-bold">Rata-rata Nilai Per Kelas</div>
            <div className="card-body">
              {barData && <Bar options={{ responsive: true, plugins: { legend: { position: 'top' as const } } }} data={barData} />}
            </div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card card-dashboard shadow-sm">
            <div className="card-header bg-white fw-bold">Persentase Ketuntasan</div>
            <div className="card-body d-flex justify-content-center">
               <div style={{ width: '80%' }}>
                  {pieData && <Pie data={pieData} />}
               </div>
            </div>
          </div>
        </div>
      </div>

      <div className="alert alert-light border mt-4">
         <strong>Informasi Kurikulum Merdeka:</strong>
         <ul className="mb-0 mt-2 text-muted small">
            <li>KKM: {KKM}</li>
            <li>Nilai Akhir = ({WEIGHTS.FORMATIF*100}% Formatif) + ({WEIGHTS.SUMATIF*100}% Sumatif Materi) + ({WEIGHTS.SAS*100}% Sumatif Akhir)</li>
         </ul>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Student, Classroom, Gender } from '../types';
import { getStudents, saveStudent, deleteStudent, getClasses, getUserProfile } from '../services/storageService';
import { SCHOOL_NAME, KEMENAG_LOGO_URL, KOP_ADDRESS } from '../constants';

export const StudentManager: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterClass, setFilterClass] = useState('');

  // Pagination state
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const [form, setForm] = useState<Partial<Student>>({
    nisn: '', name: '', gender: Gender.L, classId: ''
  });
  const [editingId, setEditingId] = useState<string | null>(null);

  useEffect(() => {
    refresh();
    setClasses(getClasses());
  }, []);

  const refresh = () => setStudents(getStudents());

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.classId) return;

    const student: Student = {
      id: editingId || Date.now().toString(),
      nisn: form.nisn || '',
      name: form.name,
      gender: form.gender || Gender.L,
      classId: form.classId
    };

    saveStudent(student);
    setForm({ nisn: '', name: '', gender: Gender.L, classId: form.classId }); // Keep class selected
    setEditingId(null);
    refresh();
  };

  const handleEdit = (s: Student) => {
    setForm(s);
    setEditingId(s.id);
  };

  const handleDelete = (id: string, name: string) => {
    if (confirm(`Yakin ingin menghapus data siswa: ${name}?\n\nPERINGATAN: Data nilai dan absensi siswa ini juga akan terhapus permanen.`)) {
      deleteStudent(id);
      refresh();
    }
  };

  // Filter Logic
  const filteredStudents = students.filter(s => {
    const matchName = s.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchClass = filterClass ? s.classId === filterClass : true;
    return matchName && matchClass;
  });

  // Pagination Logic
  const totalPages = Math.ceil(filteredStudents.length / itemsPerPage);
  const currentData = filteredStudents.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // --- Export Functions (PROFESSIONAL FORMAT) ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    const userProfile = getUserProfile();
    const className = filterClass ? classes.find(c => c.id === filterClass)?.name : 'Semua Kelas';
    const fileName = `Data_Siswa_${className.replace(/\s+/g, '_')}`;
    const dateStr = new Date().toLocaleDateString('id-ID', {day: 'numeric', month: 'long', year: 'numeric'});

    // 1. Generate Rows
    let tableRows = '';
    filteredStudents.forEach((s, idx) => {
        tableRows += `
            <tr>
                <td class="text-center">${idx + 1}</td>
                <td style="mso-number-format:'@';">${s.nisn || '-'}</td> 
                <td>${s.name}</td>
                <td class="text-center">${s.gender}</td>
                <td class="text-center">${classes.find(c => c.id === s.classId)?.name || '-'}</td>
            </tr>
        `;
    });

    // 2. Generate Full HTML Document with KOP
    const contentHTML = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="utf-8">
            <title>${fileName}</title>
            <style>
                @page { size: A4 portrait; margin: 2cm; }
                body { font-family: 'Times New Roman', serif; font-size: 12pt; color: #000; }

                /* KOP SURAT STYLE */
                .kop-table { width: 100%; border-bottom: 3px double #000; margin-bottom: 20px; }
                .kop-table td { border: none; padding: 0; vertical-align: middle; }
                .kop-logo { width: 90px; text-align: center; }
                .kop-text { text-align: center; }
                .kop-text h4 { margin: 0; font-size: 14pt; font-weight: normal; }
                .kop-text h3 { margin: 0; font-size: 14pt; font-weight: bold; text-transform: uppercase; }
                .kop-text h2 { margin: 0; font-size: 16pt; font-weight: bold; text-transform: uppercase; }
                .kop-text p { margin: 0; font-size: 10pt; font-style: italic; }

                table.data-table { width: 100%; border-collapse: collapse; border-spacing: 0; margin-bottom: 20px; }
                table.data-table th, table.data-table td { border: 1px solid #000; padding: 6px 4px; font-size: 11pt; }
                table.data-table th { background-color: #f2f2f2; font-weight: bold; text-align: center; vertical-align: middle; }

                .text-center { text-align: center; }
                .text-left { text-align: left; }
                .title-doc { text-align: center; font-weight: bold; text-decoration: underline; font-size: 14pt; margin-top: 10px; margin-bottom: 5px; }
                .sub-title { text-align: center; margin-bottom: 20px; }

                .signature-section { margin-top: 40px; width: 100%; page-break-inside: avoid; }
                .signature-table { width: 100%; border: none; }
                .signature-table td { border: none; text-align: center; vertical-align: top; padding: 0; }
            </style>
        </head>
        <body>
            <!-- KOP SURAT -->
            <table class="kop-table">
                <tr>
                    <td class="kop-logo">
                        <img src="${KEMENAG_LOGO_URL}" width="85" height="85" alt="Logo Kemenag">
                    </td>
                    <td class="kop-text">
                        <h4>KEMENTERIAN AGAMA REPUBLIK INDONESIA</h4>
                        <h3>KANTOR KEMENTERIAN AGAMA KABUPATEN BULUKUMBA</h3>
                        <h2>${SCHOOL_NAME.toUpperCase()}</h2>
                        <p>${KOP_ADDRESS}</p>
                    </td>
                </tr>
            </table>

            <div class="title-doc">DATA SISWA TAHUN PELAJARAN 2024/2025</div>
            <div class="sub-title">Kelas: ${className}</div>

            <table class="data-table">
                <thead>
                    <tr>
                        <th width="5%">NO</th>
                        <th width="20%">NISN</th>
                        <th width="45%">NAMA LENGKAP</th>
                        <th width="10%">L/P</th>
                        <th width="20%">KELAS</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div class="signature-section">
                <table class="signature-table">
                    <tr>
                        <td width="65%"></td>
                        <td width="35%">
                            Bulukumba, ${dateStr}<br>
                            Guru Mata Pelajaran,<br>
                            <br><br><br><br>
                            <strong><u>${userProfile.name}</u></strong><br>
                            NIP. ${userProfile.nip || '-'}
                        </td>
                    </tr>
                </table>
            </div>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = '';
    let extension = '';

    if (type === 'excel') {
        mimeType = 'application/vnd.ms-excel';
        extension = 'xls';
    } else if (type === 'word') {
        mimeType = 'application/msword';
        extension = 'doc';
    }

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
         <h2 className="text-dark">Data Siswa</h2>
         <div className="dropdown">
            <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                📥 Backup Data
            </button>
            <ul className="dropdown-menu">
                <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel (Rapi)</button></li>
                <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word (Rapi)</button></li>
                <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
            </ul>
        </div>
      </div>

      <div className="row g-4">
        {/* Form Input */}
        <div className="col-lg-4 no-print">
          <div className="card shadow-sm border-0">
             <div className="card-header bg-success text-white fw-bold">
              {editingId ? 'Edit Siswa' : 'Tambah Siswa'}
            </div>
            <div className="card-body">
              <form onSubmit={handleSubmit}>
                 <div className="mb-3">
                  <label className="form-label">NISN</label>
                  <input
                    type="text"
                    className="form-control"
                    value={form.nisn}
                    onChange={e => setForm({...form, nisn: e.target.value})}
                  />
                </div>
                <div className="mb-3">
                  <label className="form-label">Nama Lengkap</label>
                  <input
                    type="text"
                    className="form-control"
                    value={form.name}
                    onChange={e => setForm({...form, name: e.target.value})}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label className="form-label">Jenis Kelamin</label>
                  <select
                    className="form-select"
                    value={form.gender}
                    onChange={e => setForm({...form, gender: e.target.value as Gender})}
                  >
                    <option value={Gender.L}>Laki-laki</option>
                    <option value={Gender.P}>Perempuan</option>
                  </select>
                </div>
                <div className="mb-3">
                  <label className="form-label">Kelas</label>
                  <select
                    className="form-select"
                    value={form.classId}
                    onChange={e => setForm({...form, classId: e.target.value})}
                    required
                  >
                    <option value="">Pilih Kelas...</option>
                    {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
                <div className="d-flex gap-2">
                    <button type="submit" className="btn btn-success flex-grow-1">
                      {editingId ? 'Update' : 'Simpan'}
                    </button>
                     {editingId && (
                        <button 
                            type="button" 
                            onClick={() => { setEditingId(null); setForm({ nisn: '', name: '', gender: Gender.L, classId: '' }); }}
                            className="btn btn-secondary"
                        >
                            Batal
                        </button>
                    )}
                </div>
              </form>
            </div>
          </div>
        </div>

        {/* List & Search */}
        <div className="col-lg-8">
          <div className="card shadow-sm border-0">
             <div className="card-header bg-white p-3 no-print">
                <div className="row g-2">
                    <div className="col-md-7">
                        <input
                            type="text"
                            placeholder="🔍 Cari nama siswa..."
                            className="form-control"
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <div className="col-md-5">
                        <select
                            className="form-select"
                            value={filterClass}
                            onChange={e => setFilterClass(e.target.value)}
                        >
                            <option value="">Semua Kelas</option>
                            {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                </div>
             </div>

             <div className="table-responsive">
                <table id="student-table" className="table table-hover table-striped mb-0 align-middle">
                    <thead className="table-light">
                        <tr>
                        <th className="ps-3">NISN</th>
                        <th>Nama</th>
                        <th>L/P</th>
                        <th>Kelas</th>
                        <th className="text-end pe-3 no-print">Aksi</th>
                        </tr>
                    </thead>
                    <tbody>
                        {currentData.length > 0 ? currentData.map(s => (
                        <tr key={s.id}>
                            <td className="ps-3 small text-muted">{s.nisn}</td>
                            <td className="fw-bold">{s.name}</td>
                            <td>{s.gender}</td>
                            <td>
                                <span className="badge bg-light text-dark border">
                                    {classes.find(c => c.id === s.classId)?.name || '-'}
                                </span>
                            </td>
                            <td className="text-end pe-3 no-print">
                                <button onClick={() => handleEdit(s)} className="btn btn-sm btn-link text-decoration-none">Edit</button>
                                <button onClick={() => handleDelete(s.id, s.name)} className="btn btn-sm btn-link text-danger text-decoration-none">Hapus</button>
                            </td>
                        </tr>
                        )) : (
                            <tr><td colSpan={5} className="text-center py-4 text-muted">Tidak ada data siswa ditemukan</td></tr>
                        )}
                    </tbody>
                </table>
             </div>

             {/* Pagination */}
             {totalPages > 1 && (
                 <div className="card-footer bg-white d-flex justify-content-end no-print">
                    <nav>
                        <ul className="pagination pagination-sm mb-0">
                            <li className={`page-item ${currentPage === 1 ? 'disabled' : ''}`}>
                                <button className="page-link" onClick={() => setCurrentPage(c => Math.max(c - 1, 1))}>Previous</button>
                            </li>
                            {Array.from({length: totalPages}, (_, i) => (
                                <li key={i} className={`page-item ${currentPage === i + 1 ? 'active' : ''}`}>
                                    <button className="page-link" onClick={() => setCurrentPage(i + 1)}>{i + 1}</button>
                                </li>
                            ))}
                            <li className={`page-item ${currentPage === totalPages ? 'disabled' : ''}`}>
                                <button className="page-link" onClick={() => setCurrentPage(c => Math.min(c + 1, totalPages))}>Next</button>
                            </li>
                        </ul>
                    </nav>
                 </div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Student, GradeData, Classroom } from '../types';
import { getClasses, getStudentsByClass, getGradeByStudent, saveGrade, getUserProfile } from '../services/storageService';
import { KKM, WEIGHTS, SCHOOL_NAME, KEMENAG_LOGO_URL, KOP_ADDRESS } from '../constants';

export const GradingSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [grades, setGrades] = useState<Record<string, GradeData>>({});

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      // Data students already sorted A-Z from service
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const gradeMap: Record<string, GradeData> = {};
      clsStudents.forEach(s => {
        gradeMap[s.id] = getGradeByStudent(s.id);
      });
      setGrades(gradeMap);
    }
  }, [selectedClass]);

  const handleGradeChange = (studentId: string, field: 'formatif' | 'sumatif', index: number, value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId] };
    if (field === 'formatif') {
      const newF = [...currentGrade.formatif];
      newF[index] = numVal;
      currentGrade.formatif = newF;
    } else {
      const newS = [...currentGrade.sumatif];
      newS[index] = numVal;
      currentGrade.sumatif = newS;
    }
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    saveGrade(currentGrade);
  };

  const handleSasChange = (studentId: string, field: 'sasNonTes' | 'sasTes', value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId], [field]: numVal };
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    saveGrade(currentGrade);
  };

  const getLetterGrade = (score: number) => {
      if (score >= 90) return { letter: 'A', color: 'bg-success' };
      if (score >= 80) return { letter: 'B', color: 'bg-primary' };
      if (score >= 70) return { letter: 'C', color: 'bg-info text-dark' };
      if (score >= 60) return { letter: 'D', color: 'bg-warning text-dark' };
      return { letter: 'E', color: 'bg-danger' };
  };

  // Automated Calculations & Ranking
  const calculatedData = useMemo(() => {
    // 1. Calculate scores for everyone
    const processed = students.map(s => {
      const g = grades[s.id];
      if (!g) return null;

      const validF = g.formatif.filter(n => n > 0);
      const avgF = validF.length > 0 ? validF.reduce((a, b) => a + b, 0) / validF.length : 0;

      const validS = g.sumatif.filter(n => n > 0);
      const avgS = validS.length > 0 ? validS.reduce((a, b) => a + b, 0) / validS.length : 0;

      const sas = (g.sasNonTes + g.sasTes) / 2;

      const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);
      const isPassing = final >= KKM;
      const letter = getLetterGrade(final);

      return {
        ...s,
        g, // Keep raw grades for export
        avgF,
        avgS,
        sas,
        final,
        isPassing,
        letter
      };
    });

    // 2. Determine Ranks based on Score DESC
    // Filter out nulls first
    const validProcessed = processed.filter(p => p !== null) as NonNullable<typeof processed[0]>[];

    // Sort copy by final score DESC to determine rank
    const sortedByScore = [...validProcessed].sort((a, b) => b.final - a.final);

    // Create Map for Rank
    const rankMap: Record<string, number> = {};
    sortedByScore.forEach((item, index) => {
        rankMap[item.id] = index + 1;
    });

    // 3. Return original A-Z list with Rank attached
    return validProcessed.map(item => ({
        ...item,
        rank: rankMap[item.id]
    }));

